import { GoogleGenAI } from "@google/genai";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API Key not found in environment variables");
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

export const getAgriculturalAdvice = async (query: string): Promise<string> => {
  try {
    const ai = getClient();
    const model = 'gemini-3-flash-preview';

    const systemInstruction = `
      أنت "المرشد الزراعي الذكي" لمنصة "عطاء تهامة".
      أنت خبير زراعي متخصص في بيئة تهامة اليمنية (السهل الساحلي، الأودية مثل وادي مور، وادي زبيد، وادي سهام).

      مهامك:
      1. تقديم نصائح عملية للمزارعين حول المحاصيل التهامية (المانجو، الموز، الطماطم، الدخن، الذرة).
      2. تشخيص الأمراض النباتية بناءً على الوصف وتقديم حلول (مكافحة حيوية وكيميائية آمنة).
      3. تقديم إرشادات حول الري والتسميد المناسب للتربة الرملية والطينية في تهامة.
      4. استخدام لهجة عربية واضحة ومحببة للمزارع اليمني، وتجنب المصطلحات المعقدة جداً.

      معلومات سياقية:
      - موسم الرياح (الغبار) يؤثر على المحاصيل.
      - الحرارة عالية والرطوبة عالية في الصيف.
      - الأسواق الرئيسية هي (سوق المعرص، سوق بيت الفقيه، الخ).

      إذا سأل المستخدم عن أسعار، نبهه أن الأسعار تتغير يومياً وعليه مراجعة صفحة "السوق" في التطبيق للحصول على السعر اللحظي.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: query,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
        maxOutputTokens: 1000,
      }
    });

    return response.text || "عذراً، لم أتمكن من استخلاص إجابة دقيقة. يرجى إعادة صياغة السؤال.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "نعتذر، حدث خطأ تقني في الاتصال بالمرشد الذكي. يرجى التحقق من اتصال الإنترنت والمحاولة مرة أخرى.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles, HelpCircle, Lightbulb } from 'lucide-react';
import { ChatMessage } from '../types';
import { getAgriculturalAdvice } from '../services/geminiService';

const SUGGESTED_PROMPTS = [
  "كيف أعالج ذبول الطماطم؟",
  "ما هو أفضل وقت لزراعة الذرة؟",
  "برنامج تسميد المانجو هذا الشهر",
  "طرق مكافحة دودة الحشد",
  "كيف أحافظ على رطوبة التربة؟"
];

export const AIAdvisor: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'أهلاً بك يا رفيق الأرض! 🌾\nأنا مرشدك الزراعي الخاص لمنطقة تهامة. كيف يمكنني مساعدتك اليوم لزيادة إنتاجك وحماية محصولك؟',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (textToSend: string = input) => {
    if (!textToSend.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await getAgriculturalAdvice(textToSend);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-4 h-[calc(100vh-80px)]">
      <div className="bg-white rounded-2xl shadow-xl h-full flex flex-col border border-gray-200 overflow-hidden">
        {/* Header */}
        <div className="bg-gradient-to-l from-primary-700 to-primary-600 p-4 flex items-center gap-3 shadow-md">
          <div className="bg-white/20 p-2 rounded-full backdrop-blur-sm shadow-inner">
            <Sparkles className="h-6 w-6 text-yellow-300" />
          </div>
          <div>
            <h2 className="text-white font-bold text-lg">المرشد الزراعي الذكي</h2>
            <p className="text-primary-100 text-xs opacity-90 flex items-center gap-1">
              <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
              متصل الآن (Gemini AI)
            </p>
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-[#f0f2f5]">
          {messages.map((msg) => (
            <div
              key={msg.id}
              className={`flex items-start gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-2 duration-300`}
            >
              <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 shadow-sm ${
                msg.role === 'user' ? 'bg-primary-600' : 'bg-white border border-gray-100'
              }`}>
                {msg.role === 'user' ? <User className="h-6 w-6 text-white" /> : <Bot className="h-6 w-6 text-primary-600" />}
              </div>

              <div className={`max-w-[85%] rounded-2xl px-5 py-3 shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-primary-600 text-white rounded-tl-none' 
                  : 'bg-white text-gray-800 border border-gray-100 rounded-tr-none'
              }`}>
                <p className="text-sm leading-relaxed whitespace-pre-wrap font-medium">{msg.text}</p>
                <span className={`text-[10px] block mt-1.5 opacity-70 ${
                  msg.role === 'user' ? 'text-primary-100' : 'text-gray-400'
                }`}>
                  {msg.timestamp.toLocaleTimeString('ar-YE', { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
            </div>
          ))}

          {isLoading && (
            <div className="flex items-center gap-3 mr-2 animate-pulse">
               <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center shadow-sm">
                  <Bot className="h-5 w-5 text-gray-400" />
               </div>
               <div className="bg-white px-4 py-2 rounded-full text-xs text-gray-500 font-medium shadow-sm flex items-center gap-2">
                 <Loader2 className="h-3 w-3 animate-spin" />
                 جاري الكتابة...
               </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Suggested Prompts */}
        {messages.length < 3 && !isLoading && (
          <div className="bg-[#f0f2f5] px-4 pb-2">
            <div className="flex items-center gap-2 mb-2 text-xs text-gray-500 font-bold">
               <Lightbulb className="h-3 w-3" />
               اقتراحات سريعة:
            </div>
            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
              {SUGGESTED_PROMPTS.map((prompt, idx) => (
                <button
                  key={idx}
                  onClick={() => handleSend(prompt)}
                  className="whitespace-nowrap bg-white text-primary-700 text-xs font-bold px-3 py-2 rounded-full border border-primary-100 hover:bg-primary-50 hover:border-primary-300 transition-colors shadow-sm"
                >
                  {prompt}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyPress}
              placeholder="اسأل المرشد الزراعي..."
              className="flex-1 bg-gray-50 text-gray-800 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all pl-12 border border-gray-200"
              disabled={isLoading}
            />
            <button
              onClick={() => handleSend()}
              disabled={isLoading || !input.trim()}
              className="absolute left-2 top-2 bottom-2 bg-primary-600 text-white p-2 rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:hover:bg-primary-600 transition-colors flex items-center justify-center aspect-square shadow-lg shadow-primary-200"
            >
              {isLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : <Send className="h-5 w-5 rotate-180" />}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

