import React, { useState } from 'react';
import { Search, MapPin, Tag, Plus, MessageCircle, Building2, SlidersHorizontal, ArrowDownWideNarrow, ArrowUpNarrowWide, Leaf, ShoppingBasket, Wheat, CheckCircle2, Filter } from 'lucide-react';
import { Product, ProductCategory } from '../types';

interface MarketplaceProps {
  products: Product[];
  onAddToCart: (product: Product) => void;
  onContact: (sellerId: string) => void;
  onProductClick: (product: Product) => void;
}

type SortOption = 'newest' | 'price-asc' | 'price-desc';

const CATEGORY_ICONS: Record<string, React.ReactNode> = {
  [ProductCategory.VEGETABLES]: <Leaf className="h-4 w-4" />,
  [ProductCategory.FRUITS]: <ShoppingBasket className="h-4 w-4" />,
  [ProductCategory.GRAINS]: <Wheat className="h-4 w-4" />,
  // Fallback icon
  'default': <Tag className="h-4 w-4" />
};

export const Marketplace: React.FC<MarketplaceProps> = ({ products, onAddToCart, onContact, onProductClick }) => {
  const [filter, setFilter] = useState<string>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortOption, setSortOption] = useState<SortOption>('newest');

  const filteredProducts = products.filter(p => {
    const matchesCategory = filter === 'all' || p.category === filter;
    const matchesSearch = p.name.includes(searchTerm) || p.sellerName.includes(searchTerm) || p.associationName?.includes(searchTerm);
    return matchesCategory && matchesSearch;
  }).sort((a, b) => {
    if (sortOption === 'price-asc') return a.price - b.price;
    if (sortOption === 'price-desc') return b.price - a.price;
    // Mock newest (using ID as proxy for now)
    return Number(b.id) - Number(a.id);
  });

  return (
    <div className="p-4 md:p-6 max-w-7xl mx-auto min-h-screen">

      {/* Hero Header */}
      <div className="bg-primary-800 rounded-3xl p-8 mb-8 text-white relative overflow-hidden shadow-xl">
        <div className="relative z-10 max-w-2xl">
          <h2 className="text-3xl font-bold mb-4">السوق المركزي - تهامة</h2>
          <p className="text-primary-100 text-lg mb-6">
            منصة موثوقة لبيع وشراء المحاصيل، البذور، الأسمدة والمعدات الزراعية مباشرة من المصدر.
          </p>

          <div className="bg-white p-2 rounded-xl shadow-lg flex flex-col md:flex-row gap-2">
            <div className="relative flex-1">
               <Search className="absolute right-3 top-3.5 h-5 w-5 text-gray-400" />
               <input 
                 type="text" 
                 placeholder="ابحث عن منتج (مثلاً: يوريا، بذور، طماطم)..."
                 className="w-full text-gray-800 pl-4 pr-10 py-3 rounded-lg focus:outline-none bg-transparent"
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
               />
            </div>
            <button className="bg-primary-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-primary-700 transition shadow-md">
              بحث
            </button>
          </div>
        </div>
        <div className="absolute top-0 left-0 h-full w-1/2 opacity-20 bg-[url('https://images.unsplash.com/photo-1595113316349-9fa4eb24f884?ixlib=rb-4.0.3&auto=format&fit=crop&w=1000&q=80')] bg-cover bg-center mask-image-gradient"></div>
      </div>

      {/* Filters & Categories */}
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-6 sticky top-20 z-30 bg-gray-50/95 backdrop-blur-sm py-4 border-b border-gray-200 md:border-none shadow-sm md:shadow-none rounded-b-2xl md:rounded-none px-2 md:px-0 -mx-2 md:mx-0">
         <div className="w-full md:w-auto overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
           <div className="flex gap-2">
              <button
                onClick={() => setFilter('all')}
                className={`px-5 py-2.5 rounded-full text-sm font-bold whitespace-nowrap transition-all border flex items-center gap-2 ${
                  filter === 'all' 
                    ? 'bg-gray-900 text-white border-gray-900 shadow-md transform scale-105' 
                    : 'bg-white text-gray-600 border-gray-200 hover:border-gray-400 hover:bg-gray-50'
                }`}
              >
                <Filter className="h-4 w-4" />
                الكل
              </button>
              {Object.values(ProductCategory).map((cat) => (
                <button
                  key={cat}
                  onClick={() => setFilter(cat)}
                  className={`px-5 py-2.5 rounded-full text-sm font-bold whitespace-nowrap transition-all border flex items-center gap-2 ${
                    filter === cat 
                      ? 'bg-primary-600 text-white border-primary-600 shadow-md transform scale-105' 
                      : 'bg-white text-gray-600 border-gray-200 hover:border-primary-300 hover:text-primary-700'
                  }`}
                >
                  {CATEGORY_ICONS[cat] || CATEGORY_ICONS['default']}
                  {cat}
                </button>
              ))}
           </div>
         </div>

         <div className="flex items-center gap-4 text-gray-500 text-sm font-medium w-full md:w-auto justify-end">
            <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border border-gray-200 shadow-sm">
               <SlidersHorizontal className="h-4 w-4 text-gray-400" />
               <select 
                  value={sortOption}
                  onChange={(e) => setSortOption(e.target.value as SortOption)}
                  className="bg-transparent text-gray-700 text-sm outline-none cursor-pointer pr-2"
               >
                  <option value="newest">الأحدث</option>
                  <option value="price-asc">الأقل سعراً</option>
                  <option value="price-desc">الأعلى سعراً</option>
               </select>
            </div>
         </div>
      </div>

      {/* Products Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {filteredProducts.map((product) => (
          <div 
            key={product.id} 
            className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-xl hover:translate-y-[-4px] transition-all duration-300 group flex flex-col h-full cursor-pointer relative"
            onClick={() => onProductClick(product)}
          >
            <div className="relative h-52 overflow-hidden bg-gray-100">
              <img 
                src={product.image} 
                alt={product.name} 
                className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-700" 
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-0 group-hover:opacity-40 transition-opacity duration-300"></div>

              <div className="absolute top-3 right-3 flex flex-col gap-2">
                 <span className="bg-white/95 backdrop-blur text-gray-800 text-xs font-bold px-3 py-1.5 rounded-lg flex items-center gap-1 shadow-sm">
                  {CATEGORY_ICONS[product.category] || <Tag className="h-3 w-3" />}
                  {product.category}
                </span>
              </div>

              {product.associationName && (
                <div className="absolute bottom-3 right-3 left-3">
                  <span className="bg-primary-600/90 backdrop-blur text-white text-[10px] font-medium px-2 py-1 rounded-md flex items-center gap-1 w-fit">
                    <CheckCircle2 className="h-3 w-3" />
                    موثق: {product.associationName}
                  </span>
                </div>
              )}
            </div>

            <div className="p-5 flex-1 flex flex-col">
              <div className="flex justify-between items-start mb-2">
                <h3 className="text-lg font-extrabold text-gray-800 leading-tight group-hover:text-primary-600 transition-colors">{product.name}</h3>
              </div>

              <div className="text-primary-700 font-extrabold text-xl mb-3 flex items-baseline gap-1">
                 {product.price} <span className="text-xs font-normal text-gray-500">ريال / {product.unit}</span>
              </div>

              <p className="text-gray-500 text-xs mb-4 line-clamp-2 leading-relaxed bg-gray-50 p-2 rounded-lg">{product.description}</p>

              <div className="mt-auto pt-4 border-t border-gray-50 flex flex-col gap-3">
                <div className="flex justify-between items-center text-xs text-gray-500">
                   <div className="flex items-center gap-1">
                      <MapPin className="h-3 w-3" />
                      {product.location}
                   </div>
                   <div className="font-bold text-gray-700 truncate max-w-[120px]">
                      {product.sellerName}
                   </div>
                </div>

                <div className="flex gap-2">
                  <button 
                    onClick={(e) => { e.stopPropagation(); onAddToCart(product); }}
                    className="flex-1 bg-gray-900 text-white py-2.5 rounded-xl font-bold hover:bg-primary-600 transition-colors flex items-center justify-center gap-2 text-sm shadow-lg shadow-gray-200"
                  >
                    <Plus className="h-4 w-4" />
                    إضافة للسلة
                  </button>
                  <button 
                    onClick={(e) => { e.stopPropagation(); onContact(product.sellerName); }}
                    className="px-3 bg-gray-100 text-gray-600 py-2.5 rounded-xl hover:bg-blue-50 hover:text-blue-600 transition-colors"
                    title="تواصل مع البائع"
                  >
                    <MessageCircle className="h-5 w-5" />
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredProducts.length === 0 && (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-gray-200 mt-8">
          <div className="bg-gray-50 p-6 rounded-full mb-4">
             <Search className="h-10 w-10 text-gray-300" />
          </div>
          <h3 className="text-xl font-bold text-gray-800 mb-2">لا توجد نتائج</h3>
          <p className="text-gray-500">جرب البحث بكلمات مختلفة أو تغيير التصنيف.</p>
        </div>
      )}
    </div>
  );
};

