                     </span>
                  </div>
                  {/* Quick Action Overlay */}
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <button className="bg-white text-gray-900 font-bold text-xs px-4 py-2 rounded-full shadow-lg transform scale-90 group-hover:scale-100 transition-transform">
                        عرض التفاصيل
