import React, { useState } from 'react';
import { Menu, Sprout, ShoppingCart, BarChart3, Home, BookOpen, PlusCircle, LogOut, Bell, Package, MessageCircle, Truck, LogIn } from 'lucide-react';
import { UserRole } from '../types';
import { useNavigate, useLocation } from 'react-router-dom';

interface NavigationProps {
  cartCount: number;
  userRole: UserRole | null;
  onLogout: () => void;
  hasOrders: boolean;
}

export const Navigation: React.FC<NavigationProps> = ({ cartCount, userRole, onLogout, hasOrders }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();

  // Helper to determine active state
  const isActive = (path: string) => {
    if (path === '/' && location.pathname === '/') return true;
    if (path !== '/' && location.pathname.startsWith(path)) return true;
    return false;
  };

  // Define navigation items with specific role access
  const navItems: { id: string; path: string; label: string; icon: any; roles: (UserRole | 'all')[]; hidden?: boolean }[] = [
    { 
      id: 'home', 
      path: '/',
      label: 'الرئيسية', 
      icon: Home, 
      roles: ['all'] 
    },
    { 
      id: 'market', 
      path: '/market',
      label: 'السوق', 
      icon: ShoppingCart, 
      roles: ['all'] 
    },
    { 
      id: 'orders', 
      path: '/orders',
      label: userRole === UserRole.FARMER ? 'المبيعات والطلبات' : (userRole === UserRole.ASSOCIATION ? 'متابعة الطلبات' : 'طلباتي'), 
      icon: Package, 
      roles: [UserRole.CONSUMER, UserRole.MERCHANT, UserRole.FARMER, UserRole.ASSOCIATION],
      hidden: !hasOrders
    },
    { 
      id: 'shipments', 
      path: '/shipments',
      label: 'شحنات للتوصيل', 
      icon: Truck, 
      roles: [UserRole.TRANSPORT] 
    },
    { 
      id: 'messages', 
      path: '/messages',
      label: 'الرسائل', 
      icon: MessageCircle, 
      roles: [UserRole.CONSUMER, UserRole.MERCHANT, UserRole.FARMER, UserRole.TRANSPORT, UserRole.ASSOCIATION, UserRole.ADMIN, UserRole.GUEST] 
    },
    { 
      id: 'dashboard', 
      path: '/dashboard',
      label: 'لوحة التحكم', 
      icon: BarChart3, 
      roles: [UserRole.ADMIN, UserRole.ASSOCIATION] 
    },
    { 
      id: 'add-product', 
      path: '/add-product',
      label: 'إضافة منتج', 
      icon: PlusCircle, 
      roles: [UserRole.FARMER, UserRole.MERCHANT] 
    },
    { 
      id: 'guidance', 
      path: '/guidance',
      label: 'الإرشاد', 
      icon: BookOpen, 
      roles: ['all'] 
    },
    { 
      id: 'advisor', 
      path: '/advisor',
      label: 'المرشد الذكي', 
      icon: Sprout, 
      roles: ['all'] 
    },
  ];

  const filteredItems = navItems.filter(item => {
    if (!userRole) {
      return item.roles.includes('all');
    }
    const hasRole = item.roles.includes('all') || item.roles.includes(userRole);
    const isVisible = item.hidden !== true;
    return hasRole && isVisible;
  });

  const mockNotifications = [
