// Product Slider Component
const ProductSlider = ({ title, products = [], onProductClick, onAddToCart, onViewAll }: any) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  const scroll = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const { current } = scrollRef;
      const scrollAmount = 350;
      if (direction === 'left') {
        current.scrollBy({ left: -scrollAmount, behavior: 'smooth' });
      } else {
        current.scrollBy({ left: scrollAmount, behavior: 'smooth' });
      }
    }
  };

  if (!products || products.length === 0) return null;

  return (
    <div className="relative group/slider my-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
       <div className="flex justify-between items-end mb-6 px-2">
          <h2 className="text-2xl font-bold text-gray-900 relative">
            {title}
            <span className="absolute -bottom-2 right-0 h-1.5 w-12 bg-primary-500 rounded-full"></span>
          </h2>
          <div className="flex gap-2 items-center">
             <button onClick={onViewAll} className="text-sm text-primary-600 font-bold hover:underline ml-2 hidden md:block">عرض الكل</button>
             <div className="flex gap-1">
               <button onClick={() => scroll('right')} className="bg-white border border-gray-200 p-2.5 rounded-full hover:bg-primary-50 hover:border-primary-200 text-gray-600 hover:text-primary-600 transition shadow-sm">
                  <ChevronRight className="h-5 w-5" />
               </button>
               <button onClick={() => scroll('left')} className="bg-white border border-gray-200 p-2.5 rounded-full hover:bg-primary-50 hover:border-primary-200 text-gray-600 hover:text-primary-600 transition shadow-sm">
                  <ChevronLeft className="h-5 w-5" />
               </button>
             </div>
          </div>
       </div>

       <div 
         ref={scrollRef}
         className="flex gap-5 overflow-x-auto pb-8 pt-2 px-2 scrollbar-hide snap-x snap-mandatory"
         style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
       >
         {products.map((product: Product) => (
            <div 
