                  <div className="text-xs text-gray-400 font-bold uppercase tracking-wider">التاريخ</div>
                  <div className="text-gray-900 font-medium">{order.date}</div>
                </div>
              </div>

              <div className="flex items-center gap-3">
                 <div className={`px-4 py-1.5 rounded-full border text-xs font-black flex items-center gap-2 ${getStatusColor(order.status)}`}>
                    <div className={`w-2 h-2 rounded-full animate-pulse ${order.status === 'pending' ? 'bg-amber-500' : (order.status === 'shipping' ? 'bg-blue-500' : 'bg-emerald-500')}`}></div>
                    {getStatusText(order.status)}
                 </div>
              </div>
            </div>

            <div className="p-6 grid lg:grid-cols-3 gap-8">
              {/* Column 1: Items */}
              <div className="lg:col-span-2 space-y-4">
                <h4 className="text-sm font-black text-gray-400 flex items-center gap-2 mb-2">
                   <ShoppingBag className="h-4 w-4" /> المنتجات المطلوبة
                </h4>
                {order.items.map((item, idx) => (
                  <div key={idx} className="flex items-center gap-4 bg-gray-50/50 p-3 rounded-2xl border border-gray-100">
                    <img src={item.image} alt={item.name} className="w-16 h-16 rounded-xl object-cover shadow-sm" />
                    <div className="flex-1">
                      <h5 className="font-bold text-gray-900">{item.name}</h5>
                      <p className="text-xs text-gray-500">البائع: {item.sellerName}</p>
                    </div>
                    <div className="text-left">
                      <div className="text-primary-700 font-black">{item.price * item.quantity} ر.ي</div>
                      <div className="text-xs text-gray-400">{item.quantity} x {item.unit}</div>
                    </div>
                  </div>
                ))}

                <div className="flex justify-between items-center pt-4 border-t border-dashed">
                   <span className="text-gray-500 font-bold">إجمالي قيمة الفاتورة:</span>
                   <span className="text-2xl font-black text-gray-900">{order.total} <span className="text-sm font-normal text-gray-400">ريال</span></span>
                </div>
              </div>

              {/* Column 2: Customer / Logistics */}
              <div className="bg-gray-50 rounded-3xl p-6 border border-gray-100 flex flex-col">
                <h4 className="text-sm font-black text-gray-400 flex items-center gap-2 mb-4">
                   <User className="h-4 w-4" /> معلومات العميل
                </h4>

                <div className="space-y-4 mb-8">
                   <div className="flex items-start gap-3">
                      <div className="bg-white p-2 rounded-lg border border-gray-200">
                         <User className="h-4 w-4 text-gray-400" />
                      </div>
                      <div>
                         <div className="text-xs text-gray-400">الاسم</div>
                         <div className="text-sm font-bold text-gray-800">{mockCustomerInfo.name}</div>
                      </div>
                   </div>
                   <div className="flex items-start gap-3">
                      <div className="bg-white p-2 rounded-lg border border-gray-200">
                         <Phone className="h-4 w-4 text-gray-400" />
                      </div>
                      <div>
                         <div className="text-xs text-gray-400">رقم التواصل</div>
                         <div className="text-sm font-bold text-gray-800" dir="ltr">{mockCustomerInfo.phone}</div>
                      </div>
                   </div>
                   <div className="flex items-start gap-3">
                      <div className="bg-white p-2 rounded-lg border border-gray-200">
                         <MapPin className="h-4 w-4 text-gray-400" />
                      </div>
                      <div>
                         <div className="text-xs text-gray-400">عنوان التوصيل</div>
                         <div className="text-sm font-bold text-gray-800">{mockCustomerInfo.location}</div>
                      </div>
                   </div>
                </div>

                {/* Actions */}
                <div className="mt-auto space-y-2">
                   {onUpdateStatus && (
                     <>
                        {order.status === 'pending' && (
                          <button 
                            onClick={() => onUpdateStatus(order.id, 'shipping')}
                            className="w-full bg-blue-600 text-white py-3 rounded-2xl font-bold hover:bg-blue-700 transition shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
                          >
                            <Truck className="h-5 w-5" />
                            تأكيد التجهيز والشحن
                          </button>
                        )}
                        {(order.status === 'shipping' || (isTransport && order.status === 'shipping')) && (
                          <button 
                            onClick={() => onUpdateStatus(order.id, 'delivered')}
                            className="w-full bg-emerald-600 text-white py-3 rounded-2xl font-bold hover:bg-emerald-700 transition shadow-lg shadow-emerald-200 flex items-center justify-center gap-2"
                          >
                            <CheckCircle2 className="h-5 w-5" />
                            تأكيد تسليم الطلب
                          </button>
                        )}
                     </>
                   )}

                   <button className="w-full bg-white border border-gray-200 text-gray-700 py-3 rounded-2xl font-bold hover:bg-gray-50 transition flex items-center justify-center gap-2">
                      <Phone className="h-5 w-5 text-gray-400" />
                      اتصال بالعميل
                   </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

