           <div className="absolute bottom-[-10%] left-[-10%] w-96 h-96 bg-green-400 rounded-full mix-blend-overlay filter blur-3xl"></div>
        </div>
      </div>

      {/* Featured Carousel Section */}
      <div className="mb-12">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-2xl font-black text-gray-900">منتجات مختارة</h3>
          <div className="flex gap-2">
            <button onClick={() => scrollCarousel('right')} className="p-2 rounded-full bg-white border border-gray-100 shadow-sm hover:bg-gray-50 text-gray-400 hover:text-primary-600 transition-all">
              <ChevronRight className="h-6 w-6" />
            </button>
            <button onClick={() => scrollCarousel('left')} className="p-2 rounded-full bg-white border border-gray-100 shadow-sm hover:bg-gray-50 text-gray-400 hover:text-primary-600 transition-all">
              <ChevronLeft className="h-6 w-6" />
            </button>
          </div>
        </div>
        <div 
          ref={carouselRef}
          className="flex gap-6 overflow-x-auto pb-6 scrollbar-hide snap-x"
        >
          {featuredProducts.map((product) => (
            <div 
              key={`featured-${product.id}`} 
              className="snap-start shrink-0 w-[300px] md:w-[350px] bg-white rounded-[2rem] border border-gray-100 overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 group"
            >
              <div className="relative h-48 overflow-hidden">
                <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={product.name} />
                <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
                <div className="absolute bottom-4 right-4 text-white">
                  <p className="text-xs font-bold opacity-80">{product.category}</p>
                  <h4 className="text-lg font-black">{product.name}</h4>
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); setQuickViewProduct(product); }}
                  className="absolute top-4 left-4 bg-white/20 backdrop-blur-md text-white p-2.5 rounded-2xl hover:bg-white hover:text-primary-600 transition-all opacity-0 group-hover:opacity-100 transform translate-y-2 group-hover:translate-y-0"
                >
                  <Eye className="h-5 w-5" />
                </button>
              </div>
              <div className="p-5">
                <div className="flex justify-between items-center mb-4">
                  <div className="text-primary-700 font-black text-xl">{product.price} <span className="text-xs font-normal">ر.ي</span></div>
                  <button onClick={() => onAddToCart(product)} className="bg-primary-50 text-primary-600 p-2 rounded-xl hover:bg-primary-600 hover:text-white transition-all">
                    <Plus className="h-5 w-5" />
                  </button>
                </div>
                <div className="flex items-center gap-2 text-[10px] text-gray-400 font-bold">
                  <MapPin className="h-3 w-3" />
                  {product.location}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Categories & Sort */}
      <div className="flex flex-col space-y-4 mb-8 sticky top-16 z-30 bg-gray-50/95 backdrop-blur-md py-4 -mx-4 px-4 md:mx-0 md:px-0 border-b border-gray-200 md:border-none">
         <div className="flex justify-between items-center">
            <h3 className="font-bold text-gray-800 text-lg hidden md:block">تصفية حسب الأقسام</h3>
            <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-gray-200 shadow-sm mr-auto">
               <SlidersHorizontal className="h-4 w-4 text-gray-400" />
               <select 
                  value={sortOption}
                  onChange={(e) => setSortOption(e.target.value as SortOption)}
                  className="bg-transparent text-gray-700 text-sm font-bold outline-none cursor-pointer pr-2"
               >
                  <option value="newest">الأحدث إضافة</option>
                  <option value="price-asc">الأقل سعراً</option>
                  <option value="price-desc">الأعلى سعراً</option>
               </select>
            </div>
         </div>

         <div className="relative overflow-x-auto pb-4 pt-1 scrollbar-hide flex gap-3 snap-x">
            <button
               onClick={() => setFilter('all')}
               className={`snap-start shrink-0 px-6 py-3 rounded-2xl text-sm font-bold whitespace-nowrap transition-all duration-300 border flex items-center gap-2 shadow-sm ${
               filter === 'all' 
                  ? 'bg-primary-900 text-white border-primary-900 shadow-md scale-105' 
                  : 'bg-white text-gray-600 border-gray-100 hover:border-gray-300 hover:bg-gray-50'
               }`}
            >
               <Filter className="h-4 w-4" />
               الكل
            </button>
            {Object.values(ProductCategory).map((cat) => (
               <button
               key={cat}
               onClick={() => setFilter(cat)}
               className={`snap-start shrink-0 px-5 py-3 rounded-2xl text-sm font-bold whitespace-nowrap transition-all duration-300 border flex items-center gap-3 shadow-sm ${
                  filter === cat 
                     ? 'bg-primary-600 text-white border-primary-600 shadow-lg shadow-primary-200 scale-105' 
                     : 'bg-white text-gray-600 border-gray-100 hover:border-primary-200 hover:text-primary-700 hover:bg-primary-50'
               }`}
               >
               {CATEGORY_ICONS[cat] || CATEGORY_ICONS['default']}
               {cat}
               </button>
            ))}
         </div>
      </div>

      {/* Products Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
        {filteredProducts.map((product) => {
          const stats = getDynamicStats(product.id);
          return (
            <div 
              key={product.id} 
              className="group bg-white rounded-3xl border border-gray-100 overflow-hidden hover:shadow-[0_20px_50px_rgba(0,0,0,0.08)] hover:-translate-y-2 transition-all duration-500 cursor-pointer flex flex-col h-full relative"
              onClick={() => onProductClick(product)}
            >
              {/* Image Container */}
              <div className="relative h-56 overflow-hidden bg-gray-100">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-700 ease-in-out" 
                />

                {/* Badges Overlay */}
                <div className="absolute top-3 right-3 flex flex-col gap-2 z-10">
                   <span className="bg-white/95 backdrop-blur-md text-gray-800 text-[10px] font-black px-3 py-1.5 rounded-full flex items-center gap-1.5 shadow-sm">
                    {CATEGORY_ICONS[product.category] || <Tag className="h-3 w-3" />}
                    {product.category}
                  </span>
                  {stats.isLowStock && (
                    <span className="bg-red-500/95 backdrop-blur-md text-white text-[10px] font-black px-3 py-1.5 rounded-full flex items-center gap-1 shadow-sm animate-pulse">
                      <AlertCircle className="h-3 w-3" />
                      كمية محدودة
                    </span>
                  )}
                </div>

                {/* Quick View Button Overlay */}
                <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                   <button 
                     onClick={(e) => { e.stopPropagation(); setQuickViewProduct(product); }}
                     className="bg-white text-gray-900 px-6 py-2.5 rounded-full font-black text-sm flex items-center gap-2 transform translate-y-4 group-hover:translate-y-0 transition-transform duration-300 shadow-xl"
                   >
                     <Eye className="h-4 w-4" />
                     نظرة سريعة
                   </button>
                </div>

                {product.associationName && (
                  <div className="absolute top-3 left-3 z-10">
                     <div className="bg-primary-600 text-white p-2 rounded-full shadow-lg" title={`موثق من: ${product.associationName}`}>
                        <CheckCircle2 className="h-4 w-4" />
                     </div>
                  </div>
                )}

                {/* Status bar */}
                <div className="absolute bottom-0 inset-x-0 h-1 bg-gray-200/50 backdrop-blur-sm">
                   <div className={`h-full ${stats.isLowStock ? 'bg-red-500 w-1/4' : 'bg-primary-500 w-full'}`}></div>
                </div>
              </div>

              {/* Content */}
              <div className="p-5 flex-1 flex flex-col relative">
                {/* Dynamic Price & Trend */}
                <div className="flex justify-between items-start mb-4">
                  <div className="flex flex-col">
                    <div className="flex items-baseline gap-1">
                      <span className="text-2xl font-black text-gray-900 leading-none">{product.price}</span>
                      <span className="text-xs text-gray-400 font-bold">ريال / {product.unit}</span>
                    </div>

                    {/* Price Trend indicator */}
                    <div className={`flex items-center gap-1 mt-1 text-[10px] font-black ${
                      stats.trend === 'up' ? 'text-red-500' : stats.trend === 'down' ? 'text-green-600' : 'text-gray-400'
                    }`}>
                      {stats.trend === 'up' ? <TrendingUp className="h-3 w-3" /> : stats.trend === 'down' ? <TrendingDown className="h-3 w-3" /> : <Info className="h-3 w-3" />}
                      <span>{stats.trend === 'up' ? `ارتفاع ${stats.change}%` : stats.trend === 'down' ? `انخفاض ${stats.change}%` : 'سعر مستقر'}</span>
                    </div>
                  </div>

                  <div className="bg-gray-50 px-3 py-1 rounded-lg border border-gray-100">
                    <span className="text-[10px] font-black text-gray-500">{stats.stock}</span>
                  </div>
                </div>

                <div className="mb-4">
                  <h3 className="text-lg font-extrabold text-gray-900 group-hover:text-primary-700 transition-colors mb-1 line-clamp-1">{product.name}</h3>
                  <div className="flex items-center gap-2 text-[10px] text-gray-500">
                    <MapPin className="h-3 w-3 text-primary-400" />
                    <span className="truncate">{product.location}</span>
                    <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
                    <span className="truncate font-bold text-gray-700">{product.sellerName}</span>
                  </div>
                </div>

                <p className="text-gray-500 text-xs mb-6 line-clamp-2 leading-relaxed h-8">
                   {product.description}
                </p>

                <div className="mt-auto pt-4 border-t border-gray-50 grid grid-cols-[1fr_auto] gap-2">
                   <button 
                      onClick={(e) => { e.stopPropagation(); onAddToCart(product); }}
                      className="bg-primary-600 text-white py-3 px-4 rounded-xl font-black hover:bg-primary-700 transition-all duration-300 flex items-center justify-center gap-2 text-sm shadow-lg shadow-primary-100 active:scale-95"
                    >
                      <Plus className="h-4 w-4" />
                      إضافة للسلة
                    </button>
                    <button 
                      onClick={(e) => { e.stopPropagation(); onContact(product.sellerName); }}
                      className="bg-white text-gray-400 p-3 rounded-xl hover:bg-primary-50 hover:text-primary-600 transition-all border border-gray-200 hover:border-primary-200"
                      title="تواصل مع البائع"
                    >
                      <MessageCircle className="h-5 w-5" />
                    </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {filteredProducts.length === 0 && (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-200 mt-8">
          <div className="bg-gray-50 p-6 rounded-full mb-4">
             <Search className="h-12 w-12 text-gray-300" />
          </div>
          <h3 className="text-xl font-bold text-gray-800 mb-2">لا توجد منتجات مطابقة</h3>
          <p className="text-gray-500">جرب البحث بكلمات مختلفة أو تغيير التصنيف.</p>
          <button onClick={() => {setFilter('all'); setSearchTerm('')}} className="mt-6 text-primary-600 font-bold hover:underline">
             عرض كل المنتجات
          </button>
        </div>
      )}

      {/* Quick View Modal */}
      {quickViewProduct && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto relative animate-in zoom-in-95 duration-300">
            <button 
              onClick={() => setQuickViewProduct(null)}
              className="absolute top-6 left-6 z-10 p-3 bg-white/80 backdrop-blur-md rounded-full text-gray-800 hover:bg-white hover:text-red-500 transition-all shadow-lg"
            >
              <X className="h-6 w-6" />
            </button>

            <div className="grid grid-cols-1 lg:grid-cols-2">
              <div className="h-80 lg:h-full relative overflow-hidden bg-gray-50">
                <img src={quickViewProduct.image} className="w-full h-full object-cover" alt={quickViewProduct.name} />
                <div className="absolute top-6 right-6">
                  <span className="bg-primary-600 text-white text-xs font-black px-4 py-2 rounded-full shadow-lg">
                    {quickViewProduct.category}
                  </span>
                </div>
              </div>

              <div className="p-8 lg:p-12 flex flex-col">
                <div className="mb-8">
                  <div className="flex items-center gap-2 text-primary-600 font-bold text-xs uppercase tracking-widest mb-2">
                     <CheckCircle2 className="h-4 w-4" />
                     منتج موثق
                  </div>
                  <h2 className="text-3xl font-black text-gray-900 mb-4">{quickViewProduct.name}</h2>
                  <div className="flex items-center gap-4 text-sm text-gray-500 mb-6">
                    <div className="flex items-center gap-1.5 font-bold">
                       <MapPin className="h-4 w-4 text-primary-400" />
                       {quickViewProduct.location}
                    </div>
                    <div className="w-1 h-1 bg-gray-300 rounded-full"></div>
                    <div className="font-bold">{quickViewProduct.sellerName}</div>
                  </div>

                  <div className="flex items-baseline gap-2 mb-8">
                    <span className="text-4xl font-black text-primary-700">{quickViewProduct.price}</span>
                    <span className="text-gray-400 font-bold">ريال يمني / {quickViewProduct.unit}</span>
                  </div>

                  <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100 mb-8">
                    <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-3">وصف المنتج</h4>
                    <p className="text-gray-600 leading-relaxed text-sm">
                      {quickViewProduct.description}
                    </p>
                  </div>

                  <div className="flex items-center gap-6 mb-8 border-y border-gray-100 py-6">
                    <div className="flex flex-col gap-1">
                      <span className="text-[10px] font-black text-gray-400 uppercase">التقييم</span>
                      <div className="flex items-center gap-1">
                        <Star className="h-4 w-4 text-yellow-400 fill-yellow-400" />
                        <span className="text-sm font-black text-gray-900">4.9</span>
                      </div>
                    </div>
                    <div className="w-px h-8 bg-gray-100"></div>
                    <div className="flex flex-col gap-1">
                       <span className="text-[10px] font-black text-gray-400 uppercase">الموثوقية</span>
                       <div className="flex items-center gap-1 text-blue-600">
                         <ShieldCheck className="h-4 w-4" />
                         <span className="text-sm font-black">عالية</span>
                       </div>
                    </div>
                  </div>
                </div>

                <div className="mt-auto grid grid-cols-[1fr_auto] gap-4">
                  <button 
                    onClick={() => { onAddToCart(quickViewProduct); setQuickViewProduct(null); }}
                    className="bg-primary-600 text-white py-4 px-8 rounded-2xl font-black text-lg shadow-xl shadow-primary-100 hover:bg-primary-700 transition-all flex items-center justify-center gap-3"
                  >
                    <ShoppingCart className="h-5 w-5" />
                    إضافة للسلة
                  </button>
                  <button 
                    onClick={() => { onContact(quickViewProduct.sellerName); setQuickViewProduct(null); }}
                    className="p-4 border border-gray-200 rounded-2xl text-gray-400 hover:bg-primary-50 hover:text-primary-600 hover:border-primary-200 transition-all"
                  >
                    <MessageCircle className="h-6 w-6" />
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
